"""Rozwiazania: namespaces."""

from collections.abc import Callable


def find_in_legb(local_value: str, enclosing_value: str, global_value: str) -> tuple[str, str, str]:
    enclosed = enclosing_value

    def inner() -> tuple[str, str, str]:
        local = local_value
        return local, enclosed, global_value

    return inner()


def merge_symbol_tables(local_table: dict, global_table: dict) -> dict:
    merged = dict(global_table)
    merged.update(local_table)
    return merged


def make_call_counter() -> Callable[[], int]:
    count = 0

    def increment() -> int:
        nonlocal count
        count += 1
        return count

    return increment


def is_name_global(name: str, namespace: dict) -> bool:
    return name in namespace

from solutions_namespaces import find_in_legb, merge_symbol_tables


def test_find_in_legb_order():
    assert find_in_legb("L", "E", "G") == ("L", "E", "G")


def test_merge_symbol_tables_local_wins():
    assert merge_symbol_tables({"x": 2}, {"x": 1, "y": 3}) == {"x": 2, "y": 3}

from solutions_namespaces import (
    find_in_legb,
    is_name_global,
    make_call_counter,
    merge_symbol_tables,
)


def test_find_in_legb_order():
    assert find_in_legb("L", "E", "G") == ("L", "E", "G")


def test_merge_symbol_tables_local_wins():
    assert merge_symbol_tables({"x": 2}, {"x": 1, "y": 3}) == {"x": 2, "y": 3}


def test_make_call_counter_increments():
    counter = make_call_counter()
    assert counter() == 1
    assert counter() == 2
    assert counter() == 3


def test_make_call_counter_independent():
    a = make_call_counter()
    b = make_call_counter()
    a()
    a()
    assert b() == 1  # niezalezny licznik


def test_is_name_global_found():
    assert is_name_global("VALUE", {"VALUE": 42, "x": 1}) is True


def test_is_name_global_not_found():
    assert is_name_global("y", {"VALUE": 42, "x": 1}) is False
